class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val; self.left = left; self.right = right

# --- Inorder (Left-Root-Right) — gives sorted order for BST ---
def inorder_iterative(root):
    result, stack, cur = [], [], root
    while cur or stack:
        while cur:
            stack.append(cur); cur = cur.left
        cur = stack.pop()
        result.append(cur.val)
        cur = cur.right
    return result

# --- BFS / Level-order ---
from collections import deque
def level_order(root):
    if not root: return []
    result, queue = [], deque([root])
    while queue:
        level = []
        for _ in range(len(queue)):   # process one level at a time
            node = queue.popleft()
            level.append(node.val)
            if node.left:  queue.append(node.left)
            if node.right: queue.append(node.right)
        result.append(level)
    return result

# --- DFS iterative (preorder) ---
def preorder_iterative(root):
    if not root: return []
    stack, result = [root], []
    while stack:
        node = stack.pop()
        result.append(node.val)
        if node.right: stack.append(node.right)  # right first (LIFO)
        if node.left:  stack.append(node.left)
    return result

# LCA in Binary Tree — O(N)
def lca(root, p, q):
    if not root or root == p or root == q:
        return root         # base case: found one of the targets

    left  = lca(root.left, p, q)
    right = lca(root.right, p, q)

    if left and right:
        return root         # p in left subtree, q in right → root is LCA
    return left or right    # both in same subtree → return the non-None one

# LCA in BST — O(H), leverages ordering property
def lca_bst(root, p, q):
    while root:
        if p.val < root.val and q.val < root.val:
            root = root.left    # both smaller → go left
        elif p.val > root.val and q.val > root.val:
            root = root.right   # both larger → go right
        else:
            return root         # they split → root is LCA

# Distance between two nodes = LCA depth logic
def distance_between_nodes(root, p, q):
    def depth(node, target, d):
        if not node: return -1
        if node == target: return d
        left = depth(node.left, target, d+1)
        return left if left != -1 else depth(node.right, target, d+1)
    ancestor = lca(root, p, q)
    return depth(ancestor, p, 0) + depth(ancestor, q, 0)

from collections import deque

class Codec:
    # Preorder serialization with null markers
    def serialize(self, root) -> str:
        def dfs(node):
            if not node:
                vals.append('N'); return
            vals.append(str(node.val))
            dfs(node.left); dfs(node.right)
        vals = []
        dfs(root)
        return ','.join(vals)

    def deserialize(self, data: str):
        vals = iter(data.split(','))
        def dfs():
            v = next(vals)
            if v == 'N': return None
            node = TreeNode(int(v))
            node.left = dfs()
            node.right = dfs()
            return node
        return dfs()

# BFS serialize (level-order) — produces '1,2,3,N,N,4,5'
def serialize_bfs(root):
    if not root: return ''
    q, vals = deque([root]), []
    while q:
        node = q.popleft()
        if node:
            vals.append(str(node.val))
            q.append(node.left); q.append(node.right)
        else:
            vals.append('N')
    return ','.join(vals)

import math

# BST Validation — O(N), pass valid range down
def is_valid_bst(root, lo=-math.inf, hi=math.inf):
    if not root: return True
    if not (lo < root.val < hi): return False  # out of valid range
    return (is_valid_bst(root.left, lo, root.val) and
            is_valid_bst(root.right, root.val, hi))

# Kth Smallest in BST — O(H + K) using inorder
def kth_smallest(root, k):
    stack, cur = [], root
    while True:
        while cur: stack.append(cur); cur = cur.left
        cur = stack.pop()
        k -= 1
        if k == 0: return cur.val
        cur = cur.right

# Insert in BST — O(H)
def insert_bst(root, val):
    if not root: return TreeNode(val)
    if val < root.val: root.left = insert_bst(root.left, val)
    else: root.right = insert_bst(root.right, val)
    return root

# Delete from BST — O(H)
def delete_bst(root, key):
    if not root: return None
    if key < root.val: root.left = delete_bst(root.left, key)
    elif key > root.val: root.right = delete_bst(root.right, key)
    else:
        if not root.left: return root.right
        if not root.right: return root.left
        # Two children: replace with inorder successor (smallest in right)
        succ = root.right
        while succ.left: succ = succ.left
        root.val = succ.val
        root.right = delete_bst(root.right, succ.val)
    return root
